// Групи де є наша аудиторія — українці що вчать англійську
const groups = [
  { id: '@english_ua_chat', name: 'English UA Chat', type: 'group' },
  { id: '@learn_english_ukraine', name: 'Learn English Ukraine', type: 'group' },
  { id: '@englishforuachat', name: 'English for Ukrainians Chat', type: 'group' },
  { id: '@speak_english_chat', name: 'Speak English Chat', type: 'group' },
  { id: '@english_learning_ua', name: 'English Learning UA', type: 'group' },
  { id: '@ukrainians_abroad', name: 'Ukrainians Abroad', type: 'group' },
  { id: '@ua_learning_community', name: 'UA Learning Community', type: 'group' },
  { id: '@english_with_friends_ua', name: 'English with Friends UA', type: 'group' }
];
return groups.map(g => ({ json: g }));

const content = $input.first().json.message?.content || '';

// Розбиваємо на варіанти
const variants = content.split(/\n(?=\d\.)/)
  .map(v => v.replace(/^\d\.\s*/, '').trim())
  .filter(v => v.length > 20);

// Вибираємо випадковий
const staticData = $getWorkflowStaticData('global');
if (!staticData.promoVariantIndex) staticData.promoVariantIndex = 0;
const idx = staticData.promoVariantIndex % (variants.length || 1);
staticData.promoVariantIndex = idx + 1;

const chosen = variants[idx] || variants[0] || content;

// Додаємо UTM-подібний трекер
const week = new Date().toISOString().slice(0,10);
return [{ json: { 
  text: chosen,
  variant: idx + 1,
  week,
  source: 'promo_bot'
}}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.promoHistory) staticData.promoHistory = {};

const groupId = $input.first().json.id;
const lastPosted = staticData.promoHistory[groupId];
const now = Date.now();
const TWO_WEEKS = 14 * 24 * 60 * 60 * 1000;

// Не постимо в ту саму групу частіше ніж раз на 2 тижні
if (lastPosted && (now - lastPosted) < TWO_WEEKS) {
  return []; // Пропускаємо
}

return [$input.first()];

const staticData = $getWorkflowStaticData('global');
if (!staticData.promoHistory) staticData.promoHistory = {};
if (!staticData.promoStats) staticData.promoStats = [];

const groupId = $json.id;
const groupName = $json.name;

// Оновлюємо час останнього посту
staticData.promoHistory[groupId] = Date.now();

// Зберігаємо статистику
staticData.promoStats.push({
  group: groupName,
  group_id: groupId,
  posted_at: new Date().toISOString(),
  variant: $json.variant,
  week: $json.week
});

// Останні 100 записів
if (staticData.promoStats.length > 100) {
  staticData.promoStats = staticData.promoStats.slice(-100);
}

return [{ json: { tracked: true, group: groupName } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.newMembersTracking) staticData.newMembersTracking = [];
if (!staticData.promoStats) staticData.promoStats = [];

const member = $json.message?.new_chat_member || $json.message?.new_chat_members?.[0];
const chatId = $json.message?.chat?.id;

// Перевіряємо чи постили в цю групу нещодавно
const recentPromo = staticData.promoStats.find(p => {
  const dayAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
  return new Date(p.posted_at).getTime() > dayAgo;
});

const source = recentPromo ? `promo_${recentPromo.group}` : 'organic';

staticData.newMembersTracking.push({
  user_id: member?.id,
  name: member?.first_name,
  source,
  joined_at: new Date().toISOString()
});

return [{ json: {
  user_id: member?.id,
  name: member?.first_name || 'Новачок',
  source,
  chat_id: chatId
}}];

const staticData = $getWorkflowStaticData('global');
const promoStats = staticData.promoStats || [];
const newMembers = staticData.newMembersTracking || [];

const weekAgo = new Date(Date.now() - 7*24*60*60*1000).toISOString();

const weeklyPromo = promoStats.filter(p => p.posted_at > weekAgo);
const weeklyMembers = newMembers.filter(m => m.joined_at > weekAgo);

const sources = weeklyMembers.reduce((acc, m) => {
  acc[m.source] = (acc[m.source] || 0) + 1;
  return acc;
}, {});

const sourcesText = Object.entries(sources)
  .sort(([,a],[,b]) => b-a)
  .map(([s,c]) => `  • ${s}: ${c} чол`)
  .join('\n') || '  • Немає даних';

const report = `📣 ЩОТИЖНЕВИЙ ПРОМО ЗВІТ\n\n` +
  `📤 Постів в групах: ${weeklyPromo.length}\n` +
  `👥 Нових учасників: ${weeklyMembers.length}\n\n` +
  `📍 Джерела трафіку:\n${sourcesText}\n\n` +
  `Групи де постили:\n` +
  weeklyPromo.map(p => `  • ${p.group}`).join('\n');

return [{ json: { report } }];
